import{_ as t,o as a,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"210A. Ward Clerk Staffing","description":"","frontmatter":{"title":"210A. Ward Clerk Staffing","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","staffing"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/hours-of-work/210A-ward-clerk-staffing.md","filePath":"ebas/mental-health/management-admin/hours-of-work/210A-ward-clerk-staffing.md"}'),i={name:"ebas/mental-health/management-admin/hours-of-work/210A-ward-clerk-staffing.md"};function o(s,e,l,f,d,p){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="_210a-ward-clerk-staffing" tabindex="-1">210A. Ward Clerk Staffing <a class="header-anchor" href="#_210a-ward-clerk-staffing" aria-label="Permalink to &quot;210A. Ward Clerk Staffing&quot;">​</a></h1><p>Note: This provision replicates sub-<a href="/eba/ebas/mental-health/rpn-pen-mho/classification-staffing/102-workload-management.html">clause 102.4</a> and is not in addition to those requirements.</p><p><strong>210A.1</strong> Acute Inpatient Units</p><p><strong>(a)</strong> The parties are committed to maintaining adequate staffing levels in order to promote an appropriate working environment for staff and ensure adequate levels of patient care.</p><p><strong>(b)</strong> Ward Clerk Staffing</p><p><strong>(i)</strong> An Employer will appoint sufficient ward clerks so that one ward clerk is rostered on each Acute Inpatient Unit 7 days of the week. The shift length will be a minimum of 8 hours long.</p><p><strong>(ii)</strong> A Ward Clerk may be required to undertake additional clerical related duties within their base Acute Inpatient Unit or be redeployed during the shift to another acute inpatient unit within the campus to assist with workload.</p>',7)])])}const m=t(i,[["render",o]]);export{c as __pageData,m as default};
